import{_ as t,o as a,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"LinkHub","description":"","frontmatter":{"title":"LinkHub","slug":"linkhub"},"headers":[],"relativePath":"marketer-hub/linkhub.md","filePath":"marketer-hub/linkhub.md"}'),r={name:"marketer-hub/linkhub.md"};function o(l,e,s,c,d,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Learn more about Branch’s new <a href="https://help.branch.io/docs/links-page" target="_blank" rel="noreferrer">Links Page,</a> which contains an enhanced interface that will help you build, manage, and deploy links at scale.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Use LinkHub to build, manage, and deploy links at scale through a dedicated interface in the Branch Dashboard. LinkHub also provides enhanced governance and data reporting on your Branch Links. Additionally, you get capabilities like template creation, export access, and fast search/filters.</p><h2 id="manager" tabindex="-1">Manager <a class="header-anchor" href="#manager" aria-label="Permalink to &quot;Manager&quot;">​</a></h2><p>LinkHub’s <strong>Manager</strong> tab allows you to easily organize and view all of your Branch Short Links and Ad Links in one place.</p><p>Here you&#39;ll be able to search, filter, export, and bulk publish Branch Links.</p><h4 id="create-links" tabindex="-1">Create links <a class="header-anchor" href="#create-links" aria-label="Permalink to &quot;Create links&quot;">​</a></h4><p>You can create Branch Links directly through LinkHub, and you should see a similar interface to how you were generating Branch Links in the Dashboard already. For full guides on creating Branch Links, please read the following articles:</p><ul><li><a href="./create-quick-links.html">Create Web Links</a></li><li><a href="./create-app-links.html">Create App Links</a></li><li><a href="./ad-links.html">Create Ad Links</a></li></ul><h3 id="search-and-filters" tabindex="-1">Search and filters <a class="header-anchor" href="#search-and-filters" aria-label="Permalink to &quot;Search and filters&quot;">​</a></h3><p>On the <strong>Manager</strong> tab, you can easily find the links you need using the search bar to search by title/URL. If you have Activation, you can switch between <strong>All Links</strong>, <strong>Web Short Links</strong>, <strong>App Short Links</strong>, and <strong>Custom QR Codes</strong> views. If you have Performance, you can also select a separate <strong>Ad Links</strong> view.</p><p>You can also apply the following filters to make your organization easier:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td>Archived</td><td>Filter for only archived/deleted Branch Links.</td></tr><tr><td>Unique</td><td>Filter for showing analytics unique to a user. For example: if 1 user clicks 100 times, it will count as 1. There is no concept of &quot;unique revenue&quot;; &quot;revenue&quot; is always the sum of all purchase events.</td></tr><tr><td>Link Analytics Window</td><td>Filter to only show Branch Links with attribution in a specific window.</td></tr><tr><td>Link Created Window</td><td>Filter to only show Branch Links created within a specific window.</td></tr><tr><td>Campaign</td><td>Filter for specific campaign names. Dropdown options are set when you create the Branch Link.</td></tr><tr><td>Feature</td><td>Filter for specific feature names. Dropdown options are set when you create the Branch Link.</td></tr><tr><td>Channel</td><td>Filter for specific channel names. Dropdown options are set when you create the Branch Link.</td></tr><tr><td>Tags</td><td>Filter for specific tags. Dropdown options are set when you create the Branch Link.</td></tr></tbody></table><h3 id="bulk-link-tools" tabindex="-1">Bulk link tools <a class="header-anchor" href="#bulk-link-tools" aria-label="Permalink to &quot;Bulk link tools&quot;">​</a></h3><p>When you click the <strong>Create Bulk Links</strong> button, you will be prompted to select a Link Template or upload a CSV to create bulk links. Once you select, you can begin creating standardized links in bulk, and once you&#39;re done, you can copy and/or export all links.</p><p>When using any bulk actions like bulk link creation, all of your links associated with the bulk action will be under the one <em>Collection</em>. You&#39;ll be able to:</p><ul><li>Add/edit links in bulk. Columns in the bulk editor can now be re-sized and re-arranged via drag and drop</li><li>Upload a CSV for bulk link creation</li><li>Export a CSV of both link attributes (with the bulk editor) and links (with the Link Manager table)</li><li>Create QR codes</li><li>Archive links</li><li>Delete links</li></ul><p>.png)</p><h3 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h3><p>LinkHub Manager allows you to easily view your Branch Link performance through a report similar to Branch&#39;s <a href="./dashboard-reports.html">Events/Performance Table</a>. It has the same column customizability and sorting for your measurement but specific to your Ad Links and Short Links.</p><div class="info custom-block"><p class="custom-block-title">Note</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>The Activation product only includes the <strong>Clicks</strong> metric.</p></div></div><p>:::</p><p>.png)</p><h4 id="individual-link-stats" tabindex="-1">Individual link stats <a class="header-anchor" href="#individual-link-stats" aria-label="Permalink to &quot;Individual link stats&quot;">​</a></h4><p>You can also access detailed statistics for your individuals Branch Links from the Manager tab.</p><p>Select the three-dot icon in the row of the link you are interested in, then click on the <strong>View Stats</strong> option in the dropdown that opens.</p><p>The Activation product only includes the <strong>Clicks</strong> metric.</p><p>.png)</p><p>This will take you to a page where the <code>link id</code> has already been set for you for that particular link.</p><p>.png)</p><p>You will also see a click flow count, broken out by operating system.</p><p>.png)</p><h2 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h2><p>Link Templates are a way to apply specific standardizations to Branch Links you create on the Dashboard. Read our <a href="./link-templates.html">Link Templates</a> article for more information.</p>',34)])])}const k=t(r,[["render",o]]);export{p as __pageData,k as default};
